```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::deserializer des(buffer);
    NetworkPacket packet;

    // Read packet_id
    des >> packet.packet_id;

    // Read username using prefixed adaptor
    des >> hexi::prefixed(packet.username);

    // Read score count and scores vector using read_container
    uint32_t score_count;
    des >> hexi::endian::le(score_count);
    des.read_container(packet.scores, score_count);

    // Read metadata as null-terminated string
    des >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    des.skip(des.size());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::deserializer des(buffer);
    PacketInfo info;

    // Use span() for packet_id (zero-copy view of first 4 bytes)
    auto id_span = des.span<uint32_t>(1);
    info.packet_id = *id_span.data();

    // Read username using prefixed adaptor to get string_view
    des >> hexi::prefixed(info.username);

    // Skip scores vector without reading elements
    uint32_t score_count;
    des >> hexi::endian::le(score_count);
    des.skip(score_count * sizeof(uint32_t));

    return info;
}
```

