template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance with the specified element count
    hexi::block_allocator<std::byte, element_count> allocator;

    std::cout << "Block allocator demonstration with " << element_count << " elements:" << std::endl;

    // Initial state: all blocks are in the free list (pushed during construction)
    // When we allocate, pop() is called to remove blocks from the free list

    std::cout << "\nAllocating blocks (removes from free list via pop()):" << std::endl;
    auto* block1 = allocator.allocate();
    auto* block2 = allocator.allocate();
    auto* block3 = allocator.allocate();

    std::cout << "Allocated 3 blocks. Free list now has " << (element_count - 3) << " blocks remaining." << std::endl;

    // When we deallocate, push() is called to return blocks to the free list
    std::cout << "\nDeallocating blocks (returns to free list via push()):" << std::endl;
    allocator.deallocate(block1);
    allocator.deallocate(block2);

    std::cout << "Deallocated 2 blocks. Free list now has " << (element_count - 1) << " blocks." << std::endl;

    // Additional demonstration: allocate and deallocate in different orders
    std::cout << "\nAdditional demonstration:" << std::endl;
    auto* block4 = allocator.allocate();  // Uses remaining block from initial allocation
    allocator.deallocate(block3);         // Returns to free list
    allocator.deallocate(block4);         // Returns to free list

    std::cout << "All blocks deallocated. Free list restored to " << element_count << " blocks." << std::endl;

    // The free list management ensures O(1) allocation/deallocation time
    // by maintaining the linked list of free blocks through push/pop operations
}
```

