```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor instance for the buffer
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> write_adaptor(buffer);

    // Check free space using free() before writing
    if (write_adaptor.free() < input_data.size()) {
        // Resize buffer if needed (assuming buffer can be resized)
        buffer.resize(input_data.size());
    }

    // Write the input data using write()
    write_adaptor.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor instance for the same buffer
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> read_adaptor(buffer);

    // Check readable size using size()
    std::size_t readable_size = read_adaptor.size();

    // Read the data back using read() into a new vector
    std::vector<uint8_t> output(readable_size);
    read_adaptor.read(output.data(), readable_size);

    return output;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor instance for the given buffer_data
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> adaptor(buffer_data);

    // Use copy() to peek at the specified number of bytes without advancing the read pointer
    std::vector<uint8_t> peeked_data(peek_size);
